import{_ as o,o as a,c as t,ag as r}from"./chunks/framework.Dp85HCgA.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"internals/changelog/SimpleSDMLayers.md","filePath":"internals/changelog/SimpleSDMLayers.md","lastUpdated":null}'),i={name:"internals/changelog/SimpleSDMLayers.md"};function n(l,e,s,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="v1.4.2-2026-04-01" tabindex="-1"><code>v1.4.2</code> - 2026-04-01 <a class="header-anchor" href="#v1.4.2-2026-04-01" aria-label="Permalink to &quot;`v1.4.2` - 2026-04-01 {#v1.4.2-2026-04-01}&quot;">​</a></h2><ul><li><p><strong>added</strong> functions to support shift and rotate</p></li><li><p><strong>added</strong> a function for quantile transfer</p></li></ul><h2 id="v1.4.1" tabindex="-1"><code>v1.4.1</code> <a class="header-anchor" href="#v1.4.1" aria-label="Permalink to &quot;`v1.4.1` {#v1.4.1}&quot;">​</a></h2><ul><li><p><strong>added</strong> an overload for <code>reconstruct</code> to the <code>MultivariateStats</code> extension <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/574" target="_blank" rel="noreferrer">#574</a></p></li><li><p><strong>added</strong> overloads for <code>clamp</code> and <code>clamp!</code></p></li><li><p><strong>added</strong> an overload for the <code>÷</code> operator</p></li><li><p><strong>added</strong> an overload for <code>Matrix</code> on a vector of layers</p></li><li><p><strong>added</strong> <code>reconcile</code> and <code>reconcile!</code> <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/528" target="_blank" rel="noreferrer">#528</a></p></li></ul><h2 id="v1.4.0" tabindex="-1"><code>v1.4.0</code> <a class="header-anchor" href="#v1.4.0" aria-label="Permalink to &quot;`v1.4.0` {#v1.4.0}&quot;">​</a></h2><ul><li><p><strong>added</strong> errors when layers are not compatible (as opposed to failing an assertion)</p></li><li><p><strong>added</strong> support for smarter handling of projection data <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/555" target="_blank" rel="noreferrer">#555</a></p></li><li><p><strong>fixed</strong> a bug with the strides being sometimes used in the wrong order (extremely low severity)</p></li></ul><h2 id="v1.3.5" tabindex="-1"><code>v1.3.5</code> <a class="header-anchor" href="#v1.3.5" aria-label="Permalink to &quot;`v1.3.5` {#v1.3.5}&quot;">​</a></h2><ul><li><strong>added</strong> the <code>centervalue</code> keyword argument to <code>slidingwindow</code> to pass the center value as a first argument to the function</li></ul><h2 id="v1.3.4" tabindex="-1"><code>v1.3.4</code> <a class="header-anchor" href="#v1.3.4" aria-label="Permalink to &quot;`v1.3.4` {#v1.3.4}&quot;">​</a></h2><ul><li><strong>improved</strong> the performance of <code>slidingwindow</code>/<code>slidingwindow!</code></li></ul><h2 id="v1.3.3" tabindex="-1"><code>v1.3.3</code> <a class="header-anchor" href="#v1.3.3" aria-label="Permalink to &quot;`v1.3.3` {#v1.3.3}&quot;">​</a></h2><ul><li><p><strong>added</strong> a demonstration dataset with temperature</p></li><li><p><strong>added</strong> the correct handling of scale and offset data <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/540" target="_blank" rel="noreferrer">#540</a></p></li></ul><h2 id="v1.3.2" tabindex="-1"><code>v1.3.2</code> <a class="header-anchor" href="#v1.3.2" aria-label="Permalink to &quot;`v1.3.2` {#v1.3.2}&quot;">​</a></h2><ul><li><strong>added</strong> a <code>Makie</code> compatibility entry for <code>0.24</code></li></ul><h2 id="v1.3.1" tabindex="-1"><code>v1.3.1</code> <a class="header-anchor" href="#v1.3.1" aria-label="Permalink to &quot;`v1.3.1` {#v1.3.1}&quot;">​</a></h2><ul><li><strong>fixed</strong> plotting support to use <code>Makie</code> instead of <code>MakieCore</code></li></ul><h2 id="v1.3.0" tabindex="-1"><code>v1.3.0</code> <a class="header-anchor" href="#v1.3.0" aria-label="Permalink to &quot;`v1.3.0` {#v1.3.0}&quot;">​</a></h2><ul><li><p><strong>fixed</strong> a deprecation in the syntax of MultivariateStats</p></li><li><p><strong>added</strong> the <code>reclassify</code> function to change layer values using rules <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/407" target="_blank" rel="noreferrer">#407</a></p></li><li><p><strong>added</strong> the <code>cellarea</code> function in replacement of <code>cellsize</code> <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/416" target="_blank" rel="noreferrer">#416</a></p></li></ul><h2 id="v1.2.2" tabindex="-1"><code>v1.2.2</code> <a class="header-anchor" href="#v1.2.2" aria-label="Permalink to &quot;`v1.2.2` {#v1.2.2}&quot;">​</a></h2><ul><li><strong>added</strong> a Makie extension <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/422" target="_blank" rel="noreferrer">#422</a></li></ul><h2 id="v1.2.1" tabindex="-1"><code>v1.2.1</code> <a class="header-anchor" href="#v1.2.1" aria-label="Permalink to &quot;`v1.2.1` {#v1.2.1}&quot;">​</a></h2><ul><li><p><strong>improved</strong> performance of looking up values based on coordinates by using binary search via <code>Base.Sort.searchsortedfirst</code> <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/342" target="_blank" rel="noreferrer">#342</a></p></li><li><p><strong>added</strong> (fixed) support for the <code>MultivariateStats</code> package through an extension (currently supporting PCA and variants, and whitening)</p></li><li><p><strong>added</strong> (back) <code>coarsen</code> <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/347" target="_blank" rel="noreferrer">#347</a></p></li></ul><h2 id="v1.2.0" tabindex="-1"><code>v1.2.0</code> <a class="header-anchor" href="#v1.2.0" aria-label="Permalink to &quot;`v1.2.0` {#v1.2.0}&quot;">​</a></h2><ul><li><p><strong>added</strong> support for the <code>NeutralLandscapes</code> package through an extension (not currently supporting updaters) <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/368" target="_blank" rel="noreferrer">#368</a></p></li><li><p><strong>removed</strong> <code>Requires</code> as a dependency</p></li><li><p><strong>changed</strong> the Julia version to LTS (1.10)</p></li></ul><h2 id="v1.1.1" tabindex="-1"><code>v1.1.1</code> <a class="header-anchor" href="#v1.1.1" aria-label="Permalink to &quot;`v1.1.1` {#v1.1.1}&quot;">​</a></h2><ul><li><p><strong>added</strong> an overload for clustering quality <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/356" target="_blank" rel="noreferrer">#356</a></p></li><li><p><strong>added</strong> an overload to transform a clustering result based on the vector of layers used to generate it <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/357" target="_blank" rel="noreferrer">#357</a></p></li></ul><h2 id="v1.1.0" tabindex="-1"><code>v1.1.0</code> <a class="header-anchor" href="#v1.1.0" aria-label="Permalink to &quot;`v1.1.0` {#v1.1.0}&quot;">​</a></h2><ul><li><p><strong>added</strong> an extension for <code>Clustering</code> to support <code>kmeans</code> and <code>fuzzy_cmeans</code></p></li><li><p><strong>added</strong> <code>burnin</code> and <code>burnin!</code> methods to write vectors into layers</p></li></ul><h2 id="v1.0.7" tabindex="-1"><code>v1.0.7</code> <a class="header-anchor" href="#v1.0.7" aria-label="Permalink to &quot;`v1.0.7` {#v1.0.7}&quot;">​</a></h2><ul><li><p><strong>added</strong> support for the <code>⊻</code> operator</p></li><li><p><strong>fixed</strong> the <code>show</code> method for layers (especially when returning many)</p></li></ul><h2 id="v1.0.6" tabindex="-1"><code>v1.0.6</code> <a class="header-anchor" href="#v1.0.6" aria-label="Permalink to &quot;`v1.0.6` {#v1.0.6}&quot;">​</a></h2><ul><li><strong>fixed</strong> the export of the <code>interpolate!</code> method</li></ul>',35)])])}const g=o(i,[["render",n]]);export{p as __pageData,g as default};
